#include <bits/stdc++.h>
#define int long long
using namespace std;
const int N = 10000000;
int T, r, n, m, mul[N + 10], inv[N + 10], phi[N + 10];
int prim[N / 5 + 10], tot;
bool flag[N + 10];
void getprim() {
	flag[0] = flag[1] = 1;
	for (int i = 2; i <= N; i++) {
		if (flag[i] == 0) {
			prim[tot++] = i;
		}
		for (int j = 0; j < tot && i * prim[j] <= N; j++) {
			flag[i * prim[j]]=1;
			if (i % prim[j] == 0) {
				break;
			}
		}
	}
}
int f (int a, int b, int p) {
	int ans = 1;
	while (b) {
		if (b & 1) {
			ans = ans * a % p;
		}
		a = a * a % p;
		b >>= 1;
	}
	return ans;
}
signed main() {
	ios::sync_with_stdio(0);
	cin.tie(0), cout.tie(0);
	cin >> T >> r;
	getprim ();
	mul[0] = inv[0] = inv[1] = phi[1] = 1;
	for (int i = 1; i <= N; i++) {
		if (i == r) {
			mul[i] = mul[i - 1];
		} else {
			mul[i] = i * mul[i - 1] % r;
		}
	}
	for (int i = 2, j = 0; i <= N; i++) {
		if (i == prim[j]) {
			if (i == r) {
				inv[i] = inv[i - 1];
			}else {
				inv[i] = f (i, r - 2, r) * inv[i - 1] % r;
			}
			j++;
		} else {
			inv[i] = inv[i - 1];
		}
	}
	for (int i = 2, j = 0;i <= N; i++) {
		if (i == prim[j]) {
			phi[i] = (i - 1) * phi[i - 1] % r;
			j++;
		} else {
			phi[i] = phi[i - 1];
		}
	}
	while (T--) {
		cin >> n >> m;
		if (r > m && n >= r) {
			cout << "0\n";
		} else {
			cout << mul[n] % r * phi[m] % r * inv[m] % r << "\n";
		}
	}
	return 0;
}
